import {
  Networks,
  TransactionBuilder,
  BASE_FEE,
  nativeToScVal,
  ScInt,
  xdr,
} from '@stellar/stellar-sdk'
import { Contract, SorobanRpc } from '@stellar/stellar-sdk'
import { signTransaction, getAddress } from '@stellar/freighter-api'

// ─── Config ────────────────────────────────────────────────────────────────
const NETWORK_PASSPHRASE = Networks.TESTNET
const RPC_URL = 'https://soroban-testnet.stellar.org:443'

// !! Replace this with your deployed contract ID after running:
// soroban contract deploy --wasm target/wasm32-unknown-unknown/release/contract.wasm --network testnet
const CONTRACT_ID = import.meta.env.VITE_CONTRACT_ID || 'YOUR_CONTRACT_ID_HERE'

// ─── RPC Server ───────────────────────────────────────────────────────────
const server = new SorobanRpc.Server(RPC_URL, { allowHttp: false })

// ─── Wallet helpers ───────────────────────────────────────────────────────
export async function getWalletAddress() {
  const { address } = await getAddress()
  return address
}

export async function initWallet() {
  try {
    return await getWalletAddress()
  } catch {
    return null
  }
}

export function getContractId() { return CONTRACT_ID }
export function getNetwork()    { return NETWORK_PASSPHRASE }

// ─── Core: build, simulate, sign, send ───────────────────────────────────
/**
 * Builds a Soroban transaction, simulates it, gets user signature via
 * Freighter, then sends it to the network.
 *
 * @param {string} method   - Contract function name
 * @param {xdr.ScVal[]} args - Encoded arguments
 * @returns {SorobanRpc.Api.GetSuccessfulTransactionResponse} final result
 */
async function invokeContract(method, args = []) {
  const address = await getWalletAddress()
  const account  = await server.getAccount(address)

  const contract = new Contract(CONTRACT_ID)

  // 1. Build transaction
  const tx = new TransactionBuilder(account, {
    fee: BASE_FEE,
    networkPassphrase: NETWORK_PASSPHRASE,
  })
    .addOperation(contract.call(method, ...args))
    .setTimeout(30)
    .build()

  // 2. Simulate to get footprint + resource fees
  const simResult = await server.simulateTransaction(tx)
  if (SorobanRpc.Api.isSimulationError(simResult)) {
    throw new Error(`Simulation failed: ${simResult.error}`)
  }

  // 3. Assemble (applies soroban data + resource fee from simulation)
  const preparedTx = SorobanRpc.assembleTransaction(tx, simResult).build()

  // 4. Sign via Freighter
  const { signedTxXdr } = await signTransaction(preparedTx.toXDR(), {
    networkPassphrase: NETWORK_PASSPHRASE,
    accountToSign: address,
  })

  // 5. Submit
  const sendResult = await server.sendTransaction(
    TransactionBuilder.fromXDR(signedTxXdr, NETWORK_PASSPHRASE)
  )

  if (sendResult.status === 'ERROR') {
    throw new Error(`Submit failed: ${JSON.stringify(sendResult.errorResult)}`)
  }

  // 6. Poll until confirmed
  const hash = sendResult.hash
  let getResult = await server.getTransaction(hash)

  while (getResult.status === SorobanRpc.Api.GetTransactionStatus.NOT_FOUND) {
    await new Promise(r => setTimeout(r, 1500))
    getResult = await server.getTransaction(hash)
  }

  if (getResult.status === SorobanRpc.Api.GetTransactionStatus.FAILED) {
    throw new Error('Transaction failed on-chain')
  }

  return getResult // .returnValue has the contract return
}

// ─── Read-only simulation (no signature needed) ───────────────────────────
async function readContract(method, args = []) {
  const address = await getWalletAddress()
  const account  = await server.getAccount(address)
  const contract = new Contract(CONTRACT_ID)

  const tx = new TransactionBuilder(account, {
    fee: BASE_FEE,
    networkPassphrase: NETWORK_PASSPHRASE,
  })
    .addOperation(contract.call(method, ...args))
    .setTimeout(30)
    .build()

  const simResult = await server.simulateTransaction(tx)
  if (SorobanRpc.Api.isSimulationError(simResult)) {
    throw new Error(`Read simulation failed: ${simResult.error}`)
  }

  return simResult.result?.retval ?? null
}

// ─── ScVal helpers ────────────────────────────────────────────────────────
function u64(n) {
  return new ScInt(n, { type: 'u64' }).toU64()
}

function str(env, s) {
  // Soroban String is just a Bytes-backed type; pass as ScString
  return xdr.ScVal.scvString(s)
}

// ─── Public contract functions ────────────────────────────────────────────

/**
 * mint_nft(creator_id: u64, title: String, descrip: String, total_shares: u64) → u64
 */
export async function simulateMintNFT(creatorId, title, descrip, totalShares) {
  const result = await invokeContract('mint_nft', [
    u64(creatorId),
    xdr.ScVal.scvString(title),
    xdr.ScVal.scvString(descrip),
    u64(totalShares),
  ])
  // returnValue is a ScVal u64 — the new nft_id
  return Number(result.returnValue?._value ?? 0)
}

/**
 * transfer_shares(nft_id, from_id, to_id, amount: u64)
 */
export async function simulateTransferShares(nftId, fromId, toId, amount) {
  await invokeContract('transfer_shares', [
    u64(nftId),
    u64(fromId),
    u64(toId),
    u64(amount),
  ])
}

/**
 * burn_nft(nft_id, burner_id: u64)
 */
export async function simulateBurnNFT(nftId, burnerId) {
  await invokeContract('burn_nft', [
    u64(nftId),
    u64(burnerId),
  ])
}

/**
 * view_nft(nft_id: u64) → FractionalNFT struct
 */
export async function viewNFT(nftId) {
  const val = await readContract('view_nft', [u64(nftId)])
  return parseNFTData(scMapToObject(val))
}

/**
 * view_shares(nft_id, holder_id: u64) → ShareHolder struct
 */
export async function viewShares(nftId, holderId) {
  const val = await readContract('view_shares', [u64(nftId), u64(holderId)])
  return parseShareHolderData(scMapToObject(val))
}

/**
 * view_platform_stats() → PlatformStats struct
 */
export async function viewPlatformStats() {
  const val = await readContract('view_platform_stats', [])
  return parsePlatformStats(scMapToObject(val))
}

// ─── ScVal → plain object ─────────────────────────────────────────────────
function scMapToObject(scVal) {
  if (!scVal) return null
  try {
    // scvMap is an array of { key: ScVal, val: ScVal }
    const map = scVal._value // xdr ScMap
    const obj = {}
    for (const entry of map) {
      const key   = entry.key()._value    // ScvSymbol string
      const value = entry.val()
      obj[key] = scValToJs(value)
    }
    return obj
  } catch (e) {
    console.error('scMapToObject error:', e)
    return null
  }
}

function scValToJs(val) {
  if (!val) return null
  switch (val.switch().name) {
    case 'scvU64':      return Number(val._value.low) + Number(val._value.high) * 2**32
    case 'scvBool':     return val._value
    case 'scvString':   return val._value.toString()
    case 'scvBytes':    return val._value.toString()
    case 'scvSymbol':   return val._value.toString()
    default:            return val._value
  }
}

// ─── Data parsers (unchanged API) ────────────────────────────────────────
export function parseNFTData(result) {
  if (!result) return null
  try {
    if (result.nft_id && result.nft_id !== 0) {
      return {
        nftId:       Number(result.nft_id),
        title:       result.title || 'Unknown',
        descrip:     result.descrip || '',
        totalShares: Number(result.total_shares),
        ownerShares: Number(result.owner_shares),
        isActive:    result.is_active,
        createdAt:   Number(result.created_at),
      }
    }
  } catch (e) {
    console.error('Error parsing NFT data:', e)
  }
  return null
}

export function parseShareHolderData(result) {
  if (!result) return null
  return {
    nftId:    Number(result.nft_id),
    holderId: Number(result.holder_id),
    shares:   Number(result.shares),
  }
}

export function parsePlatformStats(result) {
  if (!result) return { totalNfts: 0, totalTransfers: 0, activeNfts: 0 }
  return {
    totalNfts:      Number(result.total_nfts),
    totalTransfers: Number(result.total_transfers),
    activeNfts:     Number(result.active_nfts),
  }
}
